import secrets
import hashlib
from datetime import datetime, timedelta
from functools import wraps
from flask import Flask, request, jsonify

app = Flask(__name__)

# In-memory storage (use database in production)
users = {
    'admin': hashlib.sha256('password123'.encode()).hexdigest(),
    'user1': hashlib.sha256('mypassword'.encode()).hexdigest()
}

tokens = {}

TOKEN_EXPIRY_HOURS = 24


def generate_token():
    return secrets.token_urlsafe(32)


def verify_password(username, password):
    if username not in users:
        return False
    password_hash = hashlib.sha256(password.encode()).hexdigest()
    return users[username] == password_hash


def token_required(f):
    @wraps(f)
    def decorated(*args, **kwargs):
        token = request.headers.get('Authorization')
        
        if not token:
            return jsonify({'message': 'Token is missing'}), 401
        
        if token.startswith('Bearer '):
            token = token[7:]
        
        if token not in tokens:
            return jsonify({'message': 'Invalid token'}), 401
        
        token_data = tokens[token]
        if datetime.now() > token_data['expires_at']:
            del tokens[token]
            return jsonify({'message': 'Token has expired'}), 401
        
        request.current_user = token_data['username']
        return f(*args, **kwargs)
    
    return decorated


@app.route('/login', methods=['POST'])
def login():
    data = request.get_json()
    
    if not data or 'username' not in data or 'password' not in data:
        return jsonify({'message': 'Username and password required'}), 400
    
    username = data['username']
    password = data['password']
    
    if not verify_password(username, password):
        return jsonify({'message': 'Invalid credentials'}), 401
    
    token = generate_token()
    tokens[token] = {
        'username': username,
        'created_at': datetime.now(),
        'expires_at': datetime.now() + timedelta(hours=TOKEN_EXPIRY_HOURS)
    }
    
    return jsonify({
        'message': 'Login successful',
        'token': token,
        'expires_in': f'{TOKEN_EXPIRY_HOURS} hours'
    }), 200


@app.route('/logout', methods=['POST'])
@token_required
def logout():
    token = request.headers.get('Authorization')
    if token.startswith('Bearer '):
        token = token[7:]
    
    if token in tokens:
        del tokens[token]
    
    return jsonify({'message': 'Logout successful'}), 200


@app.route('/protected', methods=['GET'])
@token_required
def protected():
    return jsonify({
        'message': 'Access granted to protected resource',
        'user': request.current_user
    }), 200


@app.route('/profile', methods=['GET'])
@token_required
def profile():
    return jsonify({
        'username': request.current_user,
        'message': 'This is your profile'
    }), 200


@app.route('/verify', methods=['GET'])
@token_required
def verify():
    token = request.headers.get('Authorization')
    if token.startswith('Bearer '):
        token = token[7:]
    
    token_data = tokens[token]
    time_remaining = token_data['expires_at'] - datetime.now()
    
    return jsonify({
        'valid': True,
        'username': request.current_user,
        'expires_in_seconds': int(time_remaining.total_seconds())
    }), 200


if __name__ == '__main__':
    app.run(debug=True, port=5000)